use std::{env, fs, path::{Path, PathBuf}, process::Command};

fn main() {
    // Check for required generated files before compilation
    check_generated_files();

    let target = env::var("TARGET").unwrap_or_default();

    // Configure dynamic linking when link-dynamic feature is enabled
    if env::var("CARGO_FEATURE_LINK_DYNAMIC").is_ok() {
        configure_dynamic_linking(&target);
    }

    // Configure Python extension linking on macOS
    #[cfg(target_os = "macos")]
    {
        if env::var("CARGO_FEATURE_PYO3").is_ok() {
            println!("cargo:rustc-cdylib-link-arg=-undefined");
            println!("cargo:rustc-cdylib-link-arg=dynamic_lookup");
        }
    }

    // iOS-specific setup
    if !target.contains("ios") {
        return;
    }

    // Allow users to opt-out of the automatic configuration.
    if env::var("AZUL_IOS_SETUP").unwrap_or_default() == "disable" {
        println!(
            "cargo:warning=AZUL_IOS_SETUP is disabled. Skipping automatic iOS project \
             configuration."
        );
        return;
    }

    // --- Prerequisite Checks ---
    check_xcode_cli_tools();
    check_ios_deploy();

    // --- Automatic Project Configuration ---
    // This part modifies the user's project to set up the Cargo runner.
    // We assume the CWD for the build script is the user's project root.
    let project_root = env::var("CARGO_MANIFEST_DIR").unwrap();
    println!(
        "cargo:warning=Azul is automatically configuring '{}' for iOS builds.",
        project_root
    );

    // Create .cargo/config.toml
    let cargo_dir = Path::new(&project_root).join(".cargo");
    fs::create_dir_all(&cargo_dir).unwrap();
    let config_path = cargo_dir.join("config.toml");
    let config_content = format!(
        r#"[target.aarch64-apple-ios]
runner = "scripts/ios-runner.sh"
"#
    );
    // Only write the file if it doesn't exist or doesn't have our runner.
    if !fs::read_to_string(&config_path)
        .unwrap_or_default()
        .contains("ios-runner.sh")
    {
        fs::write(config_path, config_content).unwrap();
        println!("cargo:warning=Created/updated .cargo/config.toml with iOS runner.");
    }

    // Create the runner script
    let scripts_dir = Path::new(&project_root).join("scripts");
    fs::create_dir_all(&scripts_dir).unwrap();
    let runner_path = scripts_dir.join("ios-runner.sh");
    let runner_content = r#"#!/bin/bash
# This script is auto-generated by Azul's build system.
set -e

# Cargo passes the path to the executable as the first argument.
EXECUTABLE_PATH="$1"
# We derive the .app bundle path from it (it's created by the user's build script).
APP_NAME=$(basename "$EXECUTABLE_PATH")
APP_BUNDLE_PATH="$(dirname "$EXECUTABLE_PATH")/${APP_NAME}.app"

echo "Deploying and launching ${APP_BUNDLE_PATH} on attached iOS device..."

# Use ios-deploy to install and launch the app.
# The --justlaunch flag tells it not to attach a debugger.
ios-deploy --bundle "${APP_BUNDLE_PATH}" --justlaunch
"#;
    fs::write(&runner_path, runner_content).unwrap();
    // Make the script executable.
    Command::new("chmod")
        .arg("+x")
        .arg(&runner_path)
        .status()
        .unwrap();

    println!("cargo:warning=Created scripts/ios-runner.sh for deploying to device.");
}

// ── Dynamic linking configuration ─────────────────────────────────────

/// Platform-specific library file name for libazul.
fn lib_filename(target: &str) -> &'static str {
    if target.contains("apple") || target.contains("darwin") {
        "libazul.dylib"
    } else if target.contains("windows") {
        "azul.dll"
    } else {
        // Linux, Android, FreeBSD, etc.
        "libazul.so"
    }
}

/// Static library file name (for diagnostics / suggestions).
fn static_lib_filename(target: &str) -> &'static str {
    if target.contains("windows") {
        "azul.lib"
    } else {
        "libazul.a"
    }
}

/// Try to find the library in a directory.  Returns the directory if found.
fn probe_dir(dir: &Path, target: &str) -> Option<PathBuf> {
    let dylib = dir.join(lib_filename(target));
    if dylib.exists() {
        return Some(dir.to_path_buf());
    }
    // On macOS, also accept a .framework bundle
    let framework = dir.join("azul.framework");
    if framework.is_dir() {
        return Some(dir.to_path_buf());
    }
    None
}

/// Configure dynamic linking for the current platform.
///
/// Search order:
/// 1. `AZUL_DLL_PATH` environment variable (comma-separated list of paths)
/// 2. `../target/release` relative to the dll crate
/// 3. `../target/debug` relative to the dll crate
///
/// Each path entry can be:
/// - An absolute path: `/usr/local/lib`
/// - A relative path:  `target/release` (resolved from workspace root)
///
/// If a directory contains only a static library (`.a` / `.lib`) instead of
/// a shared library, we link statically against the prebuilt library.
///
/// On iOS and Android, dynamic linking is not the typical deployment model
/// (libraries are embedded in the app bundle / APK).  We still allow it for
/// simulator / development builds, but print a note.
fn configure_dynamic_linking(target: &str) {
    println!("cargo:rerun-if-env-changed=AZUL_DLL_PATH");

    let manifest_dir = env::var("CARGO_MANIFEST_DIR").unwrap();
    let workspace_root = Path::new(&manifest_dir).parent().unwrap();

    // Platform notes
    if target.contains("ios") {
        println!(
            "cargo:warning=link-dynamic on iOS: libraries must be embedded in \
             the .app bundle.  Consider link-static for production iOS builds."
        );
    } else if target.contains("android") {
        println!(
            "cargo:warning=link-dynamic on Android: libazul.so must be placed \
             in the APK jniLibs/ directory for the correct ABI."
        );
    }

    // Collect candidate directories
    let mut search_dirs: Vec<PathBuf> = Vec::new();

    // 1. AZUL_DLL_PATH (comma-separated list of paths)
    let env_path = env::var("AZUL_DLL_PATH").unwrap_or_default();

    if !env_path.is_empty() {
        for entry in env_path.split(',') {
            let entry = entry.trim();
            if entry.is_empty() {
                continue;
            }
            let p = Path::new(entry);
            let resolved = if p.is_absolute() {
                p.to_path_buf()
            } else {
                // Resolve relative to workspace root
                workspace_root.join(p)
            };
            search_dirs.push(resolved);
        }
    }

    // 2. Default paths relative to workspace (only if AZUL_DLL_PATH was not set,
    //    and only if we're not building azul-dll itself — otherwise the linker
    //    finds the dylib it's currently producing and errors with
    //    "can't link a dylib with itself")
    if env_path.is_empty() {
        let out_dir = env::var("OUT_DIR").unwrap_or_default();
        let is_self_build = out_dir.contains("azul-dll") || out_dir.contains("azul_dll");
        if !is_self_build {
            search_dirs.push(workspace_root.join("target/release"));
            search_dirs.push(workspace_root.join("target/debug"));
        }
    }

    // Probe each directory for a shared library first, then static
    enum Found { Dylib(PathBuf), Static(PathBuf), None }
    let mut result = Found::None;

    // First pass: look for shared library (dylib/so/dll/framework)
    for dir in &search_dirs {
        if let Some(lib_dir) = probe_dir(dir, target) {
            result = Found::Dylib(lib_dir);
            break;
        }
    }

    // Second pass (only if no shared lib): look for static library (.a/.lib)
    if matches!(result, Found::None) {
        let static_name = static_lib_filename(target);
        for dir in &search_dirs {
            if dir.join(static_name).exists() {
                result = Found::Static(dir.clone());
                break;
            }
        }
    }

    match result {
        Found::Dylib(lib_dir) => {
            println!("cargo:rustc-link-search=native={}", lib_dir.display());
            println!("cargo:rustc-link-lib=dylib=azul");
            // Set rpath so the binary can find libazul next to itself
            if target.contains("apple") {
                println!("cargo:rustc-link-arg=-Wl,-rpath,@loader_path");
                println!("cargo:rustc-link-arg=-Wl,-rpath,@executable_path");
            } else if !target.contains("windows") {
                println!("cargo:rustc-link-arg=-Wl,-rpath,$ORIGIN");
            }
        }
        Found::Static(lib_dir) => {
            println!(
                "cargo:warning=No {} found, but {} exists in {}. \
                 Linking statically against prebuilt library.",
                lib_filename(target), static_lib_filename(target), lib_dir.display(),
            );
            println!("cargo:rustc-link-search=native={}", lib_dir.display());
            println!("cargo:rustc-link-lib=static=azul");
        }
        Found::None => {
            println!(
                "cargo:warning=Could not find {} or {} in any search path.",
                lib_filename(target), static_lib_filename(target),
            );
            println!(
                "cargo:warning=Set AZUL_DLL_PATH to the directory containing the library",
            );
            println!(
                "cargo:warning=Searched: {}",
                search_dirs.iter()
                    .map(|p| p.display().to_string())
                    .collect::<Vec<_>>()
                    .join(", "),
            );
            // Emit dylib link anyway so the linker error is clear
            println!("cargo:rustc-link-lib=dylib=azul");
        }
    }
}

/// Checks if Xcode Command Line Tools are installed.
fn check_xcode_cli_tools() {
    let status = Command::new("xcode-select").arg("-p").status();
    match status {
        Ok(s) if s.success() => { /* All good */ }
        _ => {
            panic!(
                "Xcode Command Line Tools not found. Please run 'xcode-select --install' in your \
                 terminal."
            );
        }
    }
}

/// Checks if ios-deploy is installed.
fn check_ios_deploy() {
    let status = Command::new("ios-deploy").arg("--version").status();
    match status {
        Ok(s) if s.success() => { /* All good */ }
        _ => {
            panic!(
                "'ios-deploy' not found. Please install it by running 'brew install ios-deploy'."
            );
        }
    }
}

/// Checks for required generated files based on enabled features.
/// Provides helpful error messages directing users to run the correct codegen command.
fn check_generated_files() {
    let manifest_dir = env::var("CARGO_MANIFEST_DIR").unwrap();
    let workspace_root = Path::new(&manifest_dir).parent().unwrap();
    let codegen_dir = workspace_root.join("target/codegen");

    // Check for build-dll feature (needs dll_api_build.rs)
    if env::var("CARGO_FEATURE_BUILD_DLL").is_ok() {
        let dll_api_build_path = codegen_dir.join("dll_api_build.rs");
        if !dll_api_build_path.exists() {
            panic!(
                "\n\
                ╔══════════════════════════════════════════════════════════════════════════════╗\n\
                ║                 MISSING GENERATED FILE: dll_api_build.rs                     ║\n\
                ╠══════════════════════════════════════════════════════════════════════════════╣\n\
                ║ The build-dll feature requires generated bindings that don't exist yet.     ║\n\
                ║                                                                              ║\n\
                ║ To generate all bindings, run:                                               ║\n\
                ║                                                                              ║\n\
                ║   cd doc && cargo run --release -- codegen all                               ║\n\
                ║                                                                              ║\n\
                ║ Expected file: target/codegen/dll_api_build.rs                            ║\n\
                ╚══════════════════════════════════════════════════════════════════════════════╝\n"
            );
        }
        println!("cargo:rerun-if-changed={}", dll_api_build_path.display());
    }

    // Check for link-static feature (needs dll_api_static.rs)
    if env::var("CARGO_FEATURE_LINK_STATIC").is_ok() {
        let dll_api_static_path = codegen_dir.join("dll_api_static.rs");
        if !dll_api_static_path.exists() {
            panic!(
                "\n\
                ╔══════════════════════════════════════════════════════════════════════════════╗\n\
                ║                 MISSING GENERATED FILE: dll_api_static.rs                    ║\n\
                ╠══════════════════════════════════════════════════════════════════════════════╣\n\
                ║ The link-static feature requires generated bindings that don't exist yet.   ║\n\
                ║                                                                              ║\n\
                ║ To generate all bindings, run:                                               ║\n\
                ║                                                                              ║\n\
                ║   cd doc && cargo run --release -- codegen all                               ║\n\
                ║                                                                              ║\n\
                ║ Expected file: target/codegen/dll_api_static.rs                           ║\n\
                ╚══════════════════════════════════════════════════════════════════════════════╝\n"
            );
        }
        println!("cargo:rerun-if-changed={}", dll_api_static_path.display());
    }

    // Check for link-dynamic feature (needs dll_api_dynamic.rs)
    if env::var("CARGO_FEATURE_LINK_DYNAMIC").is_ok() {
        let dll_api_dynamic_path = codegen_dir.join("dll_api_dynamic.rs");
        if !dll_api_dynamic_path.exists() {
            panic!(
                "\n\
                ╔══════════════════════════════════════════════════════════════════════════════╗\n\
                ║                MISSING GENERATED FILE: dll_api_dynamic.rs                    ║\n\
                ╠══════════════════════════════════════════════════════════════════════════════╣\n\
                ║ The link-dynamic feature requires generated bindings that don't exist yet.  ║\n\
                ║                                                                              ║\n\
                ║ To generate all bindings, run:                                               ║\n\
                ║                                                                              ║\n\
                ║   cd doc && cargo run --release -- codegen all                               ║\n\
                ║                                                                              ║\n\
                ║ Expected file: target/codegen/dll_api_dynamic.rs                          ║\n\
                ╚══════════════════════════════════════════════════════════════════════════════╝\n"
            );
        }
        println!("cargo:rerun-if-changed={}", dll_api_dynamic_path.display());
    }

    // Check for reexports.rs (needed by any link mode)
    if env::var("CARGO_FEATURE_LINK_STATIC").is_ok()
        || env::var("CARGO_FEATURE_LINK_DYNAMIC").is_ok()
        || env::var("CARGO_FEATURE_BUILD_DLL").is_ok()
    {
        let reexports_path = codegen_dir.join("reexports.rs");
        if !reexports_path.exists() {
            panic!(
                "\n\
                ╔══════════════════════════════════════════════════════════════════════════════╗\n\
                ║                   MISSING GENERATED FILE: reexports.rs                       ║\n\
                ╠══════════════════════════════════════════════════════════════════════════════╣\n\
                ║ The public Rust API requires generated re-exports that don't exist yet.     ║\n\
                ║                                                                              ║\n\
                ║ To generate all bindings, run:                                               ║\n\
                ║                                                                              ║\n\
                ║   cd doc && cargo run --release -- codegen all                               ║\n\
                ║                                                                              ║\n\
                ║ Expected file: target/codegen/reexports.rs                                ║\n\
                ╚══════════════════════════════════════════════════════════════════════════════╝\n"
            );
        }
        println!("cargo:rerun-if-changed={}", reexports_path.display());
    }

    // Check for python-extension feature
    if env::var("CARGO_FEATURE_PYTHON_EXTENSION").is_ok() {
        let python_api_path = codegen_dir.join("python_api.rs");
        if !python_api_path.exists() {
            panic!(
                "\n\
                ╔══════════════════════════════════════════════════════════════════════════════╗\n\
                ║                   MISSING GENERATED FILE: python_api.rs                      ║\n\
                ╠══════════════════════════════════════════════════════════════════════════════╣\n\
                ║ The Python extension requires generated bindings that don't exist yet.      ║\n\
                ║                                                                              ║\n\
                ║ To generate all bindings, run:                                               ║\n\
                ║                                                                              ║\n\
                ║   cd doc && cargo run --release -- codegen all                               ║\n\
                ║                                                                              ║\n\
                ║ Expected file: target/codegen/python_api.rs                               ║\n\
                ╚══════════════════════════════════════════════════════════════════════════════╝\n"
            );
        }
        println!("cargo:rerun-if-changed={}", python_api_path.display());
    }

    // Always rerun if api.json changes (the source of truth)
    let api_json_path = workspace_root.join("api.json");
    if api_json_path.exists() {
        println!("cargo:rerun-if-changed={}", api_json_path.display());
    }
}
